  1→import { useCallback, useEffect, useState } from 'react';
  2→import type { ClipboardEntry } from '../data/clipboard_data';
  3→import { MOCK_CLIPBOARD_ENTRIES } from '../data/clipboard_data';
  4→import type { ClipboardChangeEvent } from '../platform';
  5→import { getPlatform, isTauri } from '../platform';
  6→import { storageGet, storageSet } from '../utils/storage';
  7→
  8→const HISTORY_KEY = 'clipboard-history';
  9→const MAX_ENTRIES = 1000;
 10→
 11→interface StoredEntry {
 12→  id: string;
 13→  content: string;
 14→  contentType: 'text' | 'link' | 'color' | 'image';
 15→  sourceApp: string;
 16→  copiedAt: string;
 17→  pinned: boolean;
 18→}
 19→
 20→function isStoredEntryArray(value: unknown): value is StoredEntry[] {
 21→  if (!Array.isArray(value)) return false;
 22→  return value.every(
 23→    v =>
 24→      typeof v === 'object' &&
 25→      v !== null &&
 26→      'id' in v &&
 27→      typeof v.id === 'string' &&
 28→      'content' in v &&
 29→      typeof v.content === 'string' &&
 30→      'contentType' in v &&
 31→      typeof v.contentType === 'string' &&
 32→      'copiedAt' in v &&
 33→      typeof v.copiedAt === 'string' &&
 34→      'pinned' in v &&
 35→      typeof v.pinned === 'boolean',
 36→  );
 37→}
 38→
 39→function serializeEntries(entries: ClipboardEntry[]): StoredEntry[] {
 40→  return entries.map(e => ({
 41→    id: e.id,
 42→    content: e.content,
 43→    contentType: e.contentType,
 44→    sourceApp: e.sourceApp,
 45→    copiedAt: e.copiedAt.toISOString(),
 46→    pinned: e.pinned,
 47→  }));
 48→}
 49→
 50→function deserializeEntries(stored: StoredEntry[]): ClipboardEntry[] {
 51→  return stored.map(e => {
 52→    const date = new Date(e.copiedAt);
 53→    return {
 54→      id: e.id,
 55→      content: e.content,
 56→      contentType: e.contentType,
 57→      sourceApp: e.sourceApp,
 58→      sourceIcon: null,
 59→      copiedAt: isNaN(date.getTime()) ? new Date() : date,
 60→      pinned: e.pinned,
 61→    };
 62→  });
 63→}
 64→
 65→function loadEntries(): ClipboardEntry[] {
 66→  const stored = storageGet(HISTORY_KEY, isStoredEntryArray);
 67→  if (stored && stored.length > 0) {
 68→    return deserializeEntries(stored);
 69→  }
 70→  if (!isTauri) {
 71→    return MOCK_CLIPBOARD_ENTRIES.map(e => ({ ...e }));
 72→  }
 73→  return [];
 74→}
 75→
 76→function persistEntries(entries: ClipboardEntry[]) {
 77→  storageSet(HISTORY_KEY, serializeEntries(entries));
 78→}
 79→
 80→function createEntryFromEvent(event: ClipboardChangeEvent): ClipboardEntry {
 81→  return {
 82→    id: `clip-${event.timestamp}-${Math.random().toString(36).slice(2, 8)}`,
 83→    content: event.content,
 84→    contentType: event.contentType,
 85→    sourceApp: 'System',
 86→    sourceIcon: null,
 87→    copiedAt: new Date(event.timestamp),
 88→    pinned: false,
 89→  };
 90→}
 91→
 92→function trimToMaxEntries(entries: ClipboardEntry[]): ClipboardEntry[] {
 93→  if (entries.length <= MAX_ENTRIES) return entries;
 94→  const pinned = entries.filter(e => e.pinned);
 95→  const unpinned = entries.filter(e => !e.pinned);
 96→  const unpinnedLimit = Math.max(0, MAX_ENTRIES - pinned.length);
 97→  return [
 98→    ...pinned,
 99→    ...unpinned.slice(0, unpinnedLimit),
100→  ];
101→}
102→
103→export function useClipboardHistory() {
104→  const [entries, setEntries] = useState<ClipboardEntry[]>(loadEntries);
105→
106→  useEffect(() => {
107→    if (!isTauri) return;
108→
109→    let unsubscribe: (() => void) | undefined;
110→    let cancelled = false;
111→
112→    getPlatform()
113→      .clipboard.onClipboardChange((event: ClipboardChangeEvent) => {
114→        if (cancelled) return;
115→
116→        setEntries(prev => {
117→          const existing = prev.find(
118→            e => e.content === event.content && !e.pinned,
119→          );
120→
121→          let next: ClipboardEntry[];
122→          if (existing) {
123→            next = [
124→              {
125→                ...existing,
126→                copiedAt: new Date(event.timestamp),
127→              },
128→              ...prev.filter(e => e.id !== existing.id),
129→            ];
130→          } else {
131→            next = [
132→              createEntryFromEvent(event),
133→              ...prev,
134→            ];
135→          }
136→
137→          next = trimToMaxEntries(next);
138→          persistEntries(next);
139→          return next;
140→        });
141→      })
142→      .then(unsub => {
143→        if (cancelled) {
144→          unsub();
145→        } else {
146→          unsubscribe = unsub;
147→        }
148→      });
149→
150→    return () => {
151→      cancelled = true;
152→      unsubscribe?.();
153→    };
154→  }, []);
155→
156→  const togglePin = useCallback((entryId: string) => {
157→    setEntries(prev => {
158→      const next = prev.map(e =>
159→        e.id === entryId
160→          ? {
161→              ...e,
162→              pinned: !e.pinned,
163→            }
164→          : e);
165→      persistEntries(next);
166→      return next;
167→    });
168→  }, []);
169→
170→  const deleteEntry = useCallback((entryId: string) => {
171→    setEntries(prev => {
172→      const next = prev.filter(e => e.id !== entryId);
173→      persistEntries(next);
174→      return next;
175→    });
176→  }, []);
177→
178→  const clearAll = useCallback(() => {
179→    setEntries([]);
180→    persistEntries([]);
181→  }, []);
182→
183→  return {
184→    entries,
185→    togglePin,
186→    deleteEntry,
187→    clearAll,
188→  };
189→}
