30→export function getPlatform(): PlatformAPI {
31→  if (_platform) return _platform;
32→
33→  if (isTauri) {
34→    throw new Error(
35→      'Platform not initialized. Call initPlatform() before getPlatform() in Tauri mode.',
36→    );
